## 4. gRPC Proto 인터페이스 설계

파일 위치: `protobuf/src/main/proto/profile/profile.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}

// --- Request/Response 메시지 ---

message GetProfileRequest {
  string user_id = 1;
}

message GetProfileResponse {
  Profile profile = 1;
}

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname        = 2;
  optional string birth_date      = 3;  // YYYY-MM-DD
  optional string gender          = 4;  // MALE | FEMALE | OTHER
  optional string introduction    = 5;
  optional string profile_image_url = 6;
  optional int32  height          = 7;
  optional string location        = 8;
  repeated string interests       = 9;
  optional string mbti            = 10;
  optional string job             = 11;
}

message UpdateProfileResponse {
  Profile profile = 1;
}

// --- 공통 메시지 ---

message Profile {
  string user_id          = 1;
  string nickname         = 2;
  string birth_date       = 3;
  string gender           = 4;
  string introduction     = 5;
  string profile_image_url = 6;
  int32  height           = 7;
  string location         = 8;
  repeated string interests = 9;
  string mbti             = 10;
  string job              = 11;
  string updated_at       = 12;
}
```

### gRPC 서버 구현 (profile 마이크로서비스)

파일 위치: `{profile-service}/src/main/kotlin/com/maum/backend/controller/ProfileGrpcService.kt`

```kotlin
@GrpcService
class ProfileGrpcService(
    private val profileService: ProfileDomainService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getProfile(
        request: GetProfileRequest,
        responseObserver: StreamObserver<GetProfileResponse>,
    ) {
        try {
            val profile = profileService.getProfile(request.userId)
            val response = GetProfileResponse.newBuilder()
                .setProfile(profile.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND.withDescription(e.message).asRuntimeException()
            )
        }
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        try {
            val profile = profileService.updateProfile(request)
            val response = UpdateProfileResponse.newBuilder()
                .setProfile(profile.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND.withDescription(e.message).asRuntimeException()
            )
        } catch (e: IllegalArgumentException) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT.withDescription(e.message).asRuntimeException()
            )
        }
    }
}
```

